SELECT COUNT(*) FROM operation_log
AND action_type = #{actionType}
AND module_name LIKE CONCAT('%', #{moduleName}, '%')
AND operator_name LIKE CONCAT('%', #{operatorName}, '%')
AND result_status = #{resultStatus}
AND biz_no LIKE CONCAT('%', #{bizNo}, '%')

SELECT id, action_type, module_name, biz_type, biz_id, biz_no, operator_name, result_status, message, created_time FROM operation_log
AND action_type = #{actionType}
AND module_name LIKE CONCAT('%', #{moduleName}, '%')
AND operator_name LIKE CONCAT('%', #{operatorName}, '%')
AND result_status = #{resultStatus}
AND biz_no LIKE CONCAT('%', #{bizNo}, '%')
ORDER BY id DESC LIMIT #{offset}, #{pageSize}
